import { io, type Socket } from 'socket.io-client';
import { get } from 'svelte/store';
import { browser } from '$app/environment';
import { PUBLIC_WS_URL } from '$env/static/public';
import type { ServerToClientEvents, ClientToServerEvents } from '@lmh/types';
import { sessionStore, setPhase, setTurn,
         appendDelta, setLedger, recordBillVote,
         setNationalStatus, setPlayers, updatePlayerStat } from '../stores/session.js';
import { addPlayerAction, addStatRoll, setVisibility, visibilitySettings } from '../stores/gm.js';
import { addActionVote, removeActionVote, recordMyActionVote, recordPlayerVote, addVoteResult } from '../stores/votes.js';
import { pushNotification } from '../stores/notifications.js';

// Initialised at module load time so it is always defined before any
// component effect or event handler tries to call socket.emit().
// The `browser` guard prevents this running during SSR.
export let socket: Socket<ServerToClientEvents, ClientToServerEvents> =
  undefined!;

if (browser) {
  // In production, sentinel/empty means connect to the same origin as the page.
  const wsUrl =
    PUBLIC_WS_URL && PUBLIC_WS_URL !== '__SAME_ORIGIN__'
      ? PUBLIC_WS_URL
      : window.location.origin;
  socket = io(wsUrl, { transports: ['websocket', 'polling'] });

  socket.on('error',            e => console.error('WS error:', e.code, e.message));
  socket.on('phase_changed',    e => setPhase(e.phase));
  socket.on('turn_generated',   e => setTurn(e.turn, e.bills));
  socket.on('stat_delta', delta => {
    appendDelta(delta);
    // Patch the live players array so StatSidebar updates without a refresh.
    if (delta.stat === 'Approval' || delta.stat === 'Recognition' || delta.stat === 'Rizz') {
      updatePlayerStat(delta.target, delta.stat, delta.delta);
    }
    // Show a toast notification to players based on the GM visibility settings.
    const vis = get(visibilitySettings);
    if (vis.allRolls || vis.ownRolls) {
      const store = get(sessionStore) as any;
      const myPlayer = (store.players as any[])?.find((p: any) => p.id === store._playerId);
      const isOwn = myPlayer && delta.target === myPlayer.name;
      if (vis.allRolls || (vis.ownRolls && isOwn)) {
        const sign = delta.delta >= 0 ? '+' : '';
        pushNotification(
          `${delta.stat} (${delta.target}): ${sign}${delta.delta} \u2014 ${delta.reason}`,
          delta.delta >= 0,
        );
      }
    }
  });
  socket.on('ledger_finalized', e => setLedger(e.ledger, e.turnIndex, e.year));
  socket.on('vote_recorded',    e => {
    const playerId = (get(sessionStore) as any)._playerId;
    if (playerId === e.playerId) {
      recordBillVote(e.billId, e.vote);
    }
  });
  socket.on('national_status_updated', e => {
    setNationalStatus(e.financial, e.social, e.foreign);
  });
  socket.on('players_updated', e => {
    setPlayers(e.players);
  });
  socket.on('player_action_submitted', e => {
    addPlayerAction({
      actionId:   e.actionId,
      turnIndex: e.turnIndex, year: e.year,
      playerName: e.playerName, party: e.party, region: e.region,
      type: e.type, content: e.content, prompt: e.prompt,
      receivedAt: new Date().toISOString(),
    });
  });
  socket.on('action_stat_roll', e => {
    addStatRoll({
      actionId:      e.actionId,
      playerName:    e.playerName,
      actionContent: e.actionContent,
      sizeCategory:  e.sizeCategory,
      directionHint: e.directionHint,
    });
  });
  socket.on('legislative_vote_requested', e => {
    addActionVote({
      actionId: e.actionId, playerName: e.playerName, party: e.party, content: e.content,
    });
  });
  // Player votes are broadcast to all ΓÇö update live tally in vote card
  (socket as any).on('player_action_voted', (e: {actionId: string; playerName: string; vote: 'YEA'|'NAY'}) => {
    recordPlayerVote(e.actionId, e.playerName, e.vote);
  });
  // If the GM removes this player, redirect them back to lobby
  (socket as any).on('player_removed', (e: {playerId: string}) => {
    const store = get(sessionStore) as any;
    if (e.playerId === store._playerId) {
      // Clear stored identity so they can re-join as a new senator
      const session = (store as any).session;
      const sid = session?.id ?? '';
      sessionStorage.removeItem(`lmh:player:${sid}`);
      localStorage.removeItem(`lmh:player:${sid}`);
      window.location.href = `/lobby?session=${sid}&removed=1`;
    }
  });
  socket.on('action_vote_result', e => {
    removeActionVote(e.actionId);
    addVoteResult({
      actionId: e.actionId, playerName: '', content: '',
      yeas: e.yeas, nays: e.nays, abstains: e.abstains, passed: e.passed,
      resolvedAt: new Date().toISOString(),
    });
    pushNotification(
      `Legislative vote: ${e.passed ? 'PASSED' : 'FAILED'} (Yea ${e.yeas}, Nay ${e.nays}, Abstain ${e.abstains})`,
      e.passed,
    );
  });
  socket.on('visibility_updated', e => {
    setVisibility(e.settings);
  });
}

import { writable, derived } from 'svelte/store';
import type {
  SessionStore,
  TurnState,
  BillState,
  PlayerState,
  StatDeltaRecord,
  SessionMeta,
  RegionApprovalSnapshot,
  VoteOption,
  TurnPhase
} from '@lmh/types';

const INITIAL: SessionStore = {
  session: null,
  currentTurn: null,
  phase: 'LOBBY',
  players: [],
  bills: [],
  ledger: [],
  mapData: {},
  gmMode: false,
};

const { subscribe, update } = writable<SessionStore>(INITIAL);

export const sessionStore = { subscribe };
export const phase = derived(sessionStore, s => s.phase);
export const bills = derived(sessionStore, s => s.bills);
export const players = derived(sessionStore, s => s.players);
export const currentPlayerId = derived(sessionStore, s =>
  // Treat s as a SessionStore that might also have an optional _playerId field
  (s as SessionStore & { _playerId?: string})._playerId ?? null);

/**
 * Sets the session metadata for the store.
 * @param session The new session metadata to set.
 */
export function setSession(session: SessionMeta) {
  update(s => ({ ...s, session, phase: session.phase }));
}

/**
 * Sets the current phase of the session.
 * @param p The new phase to set for the session.
 */
export function setPhase(p: TurnPhase) {
  update(s => ({ ...s, phase: p }));
}

/**
 * Sets the current turn and associated bills for the session.
 * @param turn The new turn state to set.
 * @param bills The list of bills associated with the new turn.
 */
export function setTurn(turn: TurnState, bills: BillState[]) {
  update(s => ({ ...s, currentTurn: turn, bills, phase: 'VOTING' }));
}

export function setCurrentTurnOnly(turn: TurnState) {
  update(s => ({ ...s, currentTurn: turn }));
}

/**
 * Appends a new delta record to the session ledger.
 * @param delta The delta record to append.
 */
export function appendDelta(delta: StatDeltaRecord) {
  update(s => ({ ...s, ledger: [...s.ledger, delta] }));
}

/**
 * Sets the entire session ledger to the provided list of delta records.
 * @param ledger The new list of delta records to set for the session.
 */
export function setLedger(ledger: StatDeltaRecord[], turnIndex?: number, year?: number) {
  update(s => ({
    ...s,
    ledger,
    // Update session metadata with the new turn counter if provided.
    ...(s.session && turnIndex !== undefined
      ? { session: { ...s.session, turnIndex, year: year ?? s.session.year } }
      : {}),
  }));
}

/**
 * Sets the GM mode for the session.
 * @param gmMode The new GM mode to set for the session.
 */
export function setGMMode(gmMode: boolean) {
  update(s => ({ ...s, gmMode }));
}

/**
 * Sets the player ID for the current session.
 * @param id The player ID to set.
 */
export function setPlayerId(id: string) {
  update(s => ({ ...(s as any), _playerId: id }));
}

export function setPlayers(p: PlayerState[]) {
  update(s => ({ ...s, players: p }));
}

export function updatePlayerStat(
  playerName: string,
  stat: 'Approval' | 'Recognition' | 'Rizz',
  delta: number,
) {
  const col = stat.toLowerCase() as 'approval' | 'recognition' | 'rizz';
  update(s => ({
    ...s,
    players: s.players.map(p =>
      p.name === playerName ? { ...p, [col]: (p[col] as number) + delta } : p
    ),
  }));
}

export function setMapData(mapData: RegionApprovalSnapshot) {
  update(s => ({ ...s, mapData }));
}

export function setNationalStatus(financial: string, social: string, foreign: string) {
  update(s => {
    if (!s.currentTurn) return s;
    return { ...s, currentTurn: { ...s.currentTurn, nationalStatus: { financial, social, foreign } } };
  });
}

export function recordBillVote(billId: string, vote: VoteOption) {
  update(s => ({
    ...s,
    bills: s.bills.map(b => b.id === billId ? { ...b, playerVote: vote } : b),
  }));
}
